import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

const Register = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    branch: 'CSE',
    semester: '1'
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();
  const { login } = useAuth();

  const branches = ['CSE', 'ECE', 'EEE', 'Mechanical', 'Civil', 'IT', 'Other'];
  const semesters = ['1', '2', '3', '4', '5', '6', '7', '8'];

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    // Validation
    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match');
      setLoading(false);
      return;
    }

    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters');
      setLoading(false);
      return;
    }

    try {
      const response = await fetch('http://localhost:5000/api/auth/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          name: formData.name,
          email: formData.email,
          password: formData.password,
          branch: formData.branch,
          semester: parseInt(formData.semester)
        }),
      });

      const data = await response.json();

      if (response.ok) {
        setSuccess('✅ Registration successful!');
        
        // Auto login after registration
        const loginResponse = await fetch('http://localhost:5000/api/auth/login', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            email: formData.email,
            password: formData.password
          }),
        });

        const loginData = await loginResponse.json();
        
        if (loginResponse.ok) {
          login(loginData.user, loginData.access_token);
          setTimeout(() => {
            navigate('/');
          }, 1500);
        } else {
          navigate('/login');
        }
      } else {
        setError(data.error || 'Registration failed');
      }
    } catch (err) {
      setError('Network error. Check backend connection.');
    } finally {
      setLoading(false);
    }
  };

  const styles = {
    container: {
      maxWidth: '500px',
      margin: '0 auto',
      padding: '2rem 1rem',
      minHeight: '80vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    },
    card: {
      width: '100%',
      background: 'white',
      padding: '2.5rem',
      borderRadius: '15px',
      boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
    },
    title: {
      textAlign: 'center',
      marginBottom: '2rem',
      color: '#1f2937',
      fontSize: '2rem'
    },
    formGroup: {
      marginBottom: '1.5rem'
    },
    label: {
      display: 'block',
      marginBottom: '0.5rem',
      fontWeight: '500',
      color: '#374151'
    },
    input: {
      width: '100%',
      padding: '0.75rem',
      borderRadius: '8px',
      border: '1px solid #d1d5db',
      fontSize: '1rem',
      transition: 'border 0.3s',
      '&:focus': {
        borderColor: '#4f46e5',
        boxShadow: '0 0 0 3px rgba(79, 70, 229, 0.1)',
        outline: 'none'
      }
    },
    select: {
      width: '100%',
      padding: '0.75rem',
      borderRadius: '8px',
      border: '1px solid #d1d5db',
      fontSize: '1rem',
      background: 'white',
      '&:focus': {
        borderColor: '#4f46e5',
        outline: 'none'
      }
    },
    button: {
      width: '100%',
      padding: '0.875rem',
      background: '#4f46e5',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      fontSize: '1rem',
      fontWeight: '500',
      cursor: 'pointer',
      marginTop: '1rem',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#4338ca',
        transform: 'translateY(-2px)'
      },
      '&:disabled': {
        background: '#9ca3af',
        cursor: 'not-allowed',
        transform: 'none'
      }
    },
    error: {
      background: '#fee2e2',
      color: '#dc2626',
      padding: '0.75rem',
      borderRadius: '8px',
      marginBottom: '1rem',
      textAlign: 'center'
    },
    success: {
      background: '#d1fae5',
      color: '#065f46',
      padding: '0.75rem',
      borderRadius: '8px',
      marginBottom: '1rem',
      textAlign: 'center'
    },
    loginLink: {
      textAlign: 'center',
      marginTop: '1.5rem',
      color: '#6b7280'
    },
    link: {
      color: '#4f46e5',
      textDecoration: 'none',
      fontWeight: '500'
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>📝 Create Account</h2>
        
        {error && (
          <div style={styles.error}>❌ {error}</div>
        )}
        
        {success && (
          <div style={styles.success}>{success}</div>
        )}
        
        <form onSubmit={handleSubmit}>
          <div style={styles.formGroup}>
            <label style={styles.label}>Full Name</label>
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              required
              style={styles.input}
              placeholder="Enter your full name"
            />
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Email Address</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              required
              style={styles.input}
              placeholder="student@example.com"
            />
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Branch</label>
            <select
              name="branch"
              value={formData.branch}
              onChange={handleChange}
              style={styles.select}
              required
            >
              {branches.map(branch => (
                <option key={branch} value={branch}>{branch}</option>
              ))}
            </select>
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Semester</label>
            <select
              name="semester"
              value={formData.semester}
              onChange={handleChange}
              style={styles.select}
              required
            >
              {semesters.map(sem => (
                <option key={sem} value={sem}>Semester {sem}</option>
              ))}
            </select>
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Password</label>
            <input
              type="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              required
              style={styles.input}
              placeholder="At least 6 characters"
            />
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Confirm Password</label>
            <input
              type="password"
              name="confirmPassword"
              value={formData.confirmPassword}
              onChange={handleChange}
              required
              style={styles.input}
              placeholder="Re-enter your password"
            />
          </div>
          
          <button
            type="submit"
            disabled={loading}
            style={{
              ...styles.button,
              background: loading ? '#9ca3af' : '#4f46e5'
            }}
          >
            {loading ? 'Creating Account...' : 'Create Account'}
          </button>
        </form>
        
        <div style={styles.loginLink}>
          <p>Already have an account? <Link to="/login" style={styles.link}>Login here</Link></p>
        </div>
        
        <div style={{
          marginTop: '2rem',
          padding: '1rem',
          background: '#f3f4f6',
          borderRadius: '8px',
          fontSize: '0.9rem',
          color: '#6b7280'
        }}>
          <p style={{ marginBottom: '0.5rem', fontWeight: '500' }}>Why register?</p>
          <ul style={{ margin: 0, paddingLeft: '1.5rem' }}>
            <li>Upload study materials</li>
            <li>Track your downloads</li>
            <li>Get credit for contributions</li>
            <li>Access community features</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default Register;
